"""GENERATED mono-synthesis assets — inlined so N-mono sessions build with NO external
control files. Regenerate via `donorpack.write_mono_data(control_root)`. Sources:
'8 mono tracks.ptx' (scaffold, base_n=8) + '512 mono tracks.ptx' (track-2/10/100 = 1/2/3-digit
unit templates). TEMPLATE_LEAF = the templates' embedded folder leaf (normalized to the
scaffold's leaf at build time). Handle/blob are free (PT needs only their presence)."""
import base64 as _b64, zlib as _z
from . import body_synth as _B

TEMPLATE_LEAF = '512 tracks'
_SCAFFOLD = ""
_TMPL1 = ""
_TMPL2 = ""
_TMPL3 = ""

def _dec(s): return _z.decompress(_b64.b64decode(s))
def _unit(blob):
    o = 0; bs = []
    for _ in range(8):
        n = int.from_bytes(blob[o:o + 4], "little"); o += 4; bs.append(blob[o:o + n]); o += n
    return _B.StereoTrackUnit(b1014=bs[0], b1052=(bs[1],), b251a=(bs[2], bs[3]),
                              b210b=bs[4], b261c=bs[5], b2589=bs[6], name_entry=bs[7])

def mono_scaffold(): return _dec(_SCAFFOLD)          # 8-track mono clean session (base_n=8)
def mono_templates():                                # (1-digit, 2-digit, 3-digit)
    return _unit(_dec(_TMPL1)), _unit(_dec(_TMPL2)), _unit(_dec(_TMPL3))
